<template>
  <n-layout class="content">
    <n-layout-content class="content-center">
      <n-scrollbar>
        <n-grid cols="1 s:3 m:6 l:6 xl:6 2xl:6" item-responsive responsive="screen">
          <n-gi span="2">
            <n-divider dashed style="height:0px">传感器设置</n-divider>
            <n-space justify="center">
              <n-descriptions
                label-placement="left"
                bordered
                :column="1"
                label-align="center"
                size="small"
              >
                <n-descriptions-item label="左立柱压力">
                  <n-switch
                    
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.l_pillar_pressure_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.l_pillar_pressure_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>

                <n-descriptions-item label="右立柱压力">
                  <n-switch
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.r_pillar_pressure_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.r_pillar_pressure_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                

                <n-descriptions-item label="推移距离">
                  <n-switch
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.push_displacement_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.push_displacement_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                
                <n-descriptions-item label="顶板高度">
                  <n-switch
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.top_plate_height_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.top_plate_height_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                
                <n-descriptions-item label="倾角仪">
                  <n-switch
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.top_beam_inclination_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.top_beam_inclination_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                
                <n-descriptions-item label="护帮板限位">
                  <n-switch
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.guard_plate_limit_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.guard_plate_limit_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                
                <n-descriptions-item label="红外定位">
                  <n-switch
                  
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.shearer_position_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.shearer_position_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                

                <n-descriptions-item  label="自动调直">
                  
                    <n-switch
                    
                    :disabled="privateParamLoading"
                    :loading="privateParamLoading"
                    size="medium"
                    :value="privateParam.data.auto_straighten_sensor_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>privateParam.data.auto_straighten_sensor_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                 
                  
                </n-descriptions-item>

                <!-- <n-descriptions-item label="支架参数下发">
                  <n-space>
                    <n-select
                      style="width: 80px"
                      filterable
                      v-model:value="support"
                      size="small"
                      :options="supportOptions"
                      @update:value="selectSupport"
                    />-
                    <n-select
                      style="width: 80px"
                      filterable
                      v-model:value="supportEnd"
                      size="small"
                      :options="supportOptions"
                      @update:value="selectSupportEnd"
                    />
                
                  <n-button
                      tertiary
                      round
                      type="success"
                      size="small"
                      :loading="privateParamLoading"
                      @click="setPrivate"
                    >
                      <n-icon>
                        <save />
                      </n-icon>
                    </n-button>
                  </n-space>
                </n-descriptions-item> -->
              </n-descriptions>
              <n-descriptions
                label-placement="left"
                bordered
                :column="1"
                label-align="center"
                size="small"
              >

              <n-descriptions-item label="推移零点">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="推移零点"
                    :min="0"
                    :max="9999"
                    :value="publicParam.data.shift_distance_zero_off_set"
                    @update:value="i=>publicParam.data.shift_distance_zero_off_set=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="销轴滞回补偿">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="销轴滞回补偿"
                    :min="0"
                    :max="9999"
                    :value="publicParam.data.pin_Hysteresis_compensation"
                    @update:value="i=>publicParam.data.pin_Hysteresis_compensation=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="顶板零点">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="顶板零点"
                    :min="0"
                    :max="9999"
                    :value="privateParam.data.height_of_altimeter_case"
                    @update:value="i=>privateParam.data.height_of_altimeter_case=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="R-X">
                  <span style="text-align:center;font-size:medium;">{{rx}}</span>
                  <!-- <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="R-X"
                    :min="0"
                    :max="255"
                    :value="privateParam.data.rx"
                    @update:value="i=>privateParam.data.rx=i"
                  ></n-input-number> -->
                </n-descriptions-item>
                <n-descriptions-item label="R-Y">
                  <span style="text-align:center;font-size:medium;">{{ry}}</span>
                  <!-- <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="R-Y"
                    :min="0"
                    :max="255"
                    :value="privateParam.data.ry"
                    @update:value="i=>privateParam.data.ry=i"
                  ></n-input-number> -->
                </n-descriptions-item>
                <n-descriptions-item label="F-X">
                  <span style="text-align:center;font-size:medium;">{{fx}}</span>
                  <!-- <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="F-X"
                    :min="0"
                    :max="255"
                    :value="privateParam.data.fx"
                    @update:value="i=>privateParam.data.fx=i"
                  ></n-input-number> -->
                </n-descriptions-item>
                <n-descriptions-item label="F-Y">
                  <span style="text-align:center;font-size:medium;">{{fy}}</span>
                  <!-- <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="F-Y"
                    :min="0"
                    :max="255"
                    :value="privateParam.data.fy"
                    @update:value="i=>privateParam.data.fy=i"
                  ></n-input-number> -->
                </n-descriptions-item>
                <n-descriptions-item label="程序版本号">
                  <span style="text-align:center;font-size:medium;">{{version}}</span>
                </n-descriptions-item>
            </n-descriptions>
            </n-space>
          </n-gi>
          <n-gi span="2">
            <n-divider dashed style="height:0px">工作面参数</n-divider>
            <n-space justify="space-around">
              <n-descriptions
                label-placement="left"
                bordered
                :column="2"
                label-align="center"
                size="small"
              >
                <n-descriptions-item label="首支架号">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="首支架号"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.first_support_id"
                    @update:value="i=>publicParam.data.first_support_id=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="采煤机长度">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="采煤机长度"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.shearer_length"
                    @update:value="i=>publicParam.data.shearer_length=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="尾支架号">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="尾支架号"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.tail_support_id"
                    @update:value="i=>publicParam.data.tail_support_id=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="支架中心距">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="支架中心距"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.adjacent_bracket_center_distance"
                    @update:value="i=>publicParam.data.adjacent_bracket_center_distance=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="机头折返点">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="机头折返点"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.machine_head_turning_point"
                    @update:value="i=>publicParam.data.machine_head_turning_point=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="编号方向">
                  <n-space justify="center">
                    <span style="text-align:center;font-size:medium;">{{support_sorting}}</span>
                  </n-space>
                </n-descriptions-item>

                <n-descriptions-item label="机尾折返点">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="机尾折返点"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.tail_turning_point"
                    @update:value="i=>publicParam.data.tail_turning_point=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item></n-descriptions-item>
                <n-descriptions-item label="机头割透点">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="机头割透点"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.machine_head_cut_through_point"
                    @update:value="i=>publicParam.data.machine_head_cut_through_point=i"
                  ></n-input-number>
                </n-descriptions-item>

                <n-descriptions-item></n-descriptions-item>
                <n-descriptions-item label="机尾割透点">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="机尾割透点"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.tail_cut_through_point"
                    @update:value="i=>publicParam.data.tail_cut_through_point=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item></n-descriptions-item>
                <n-descriptions-item label="自动跟机首架">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="自动跟机首架"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.auto_first_support_id"
                    @update:value="i=>publicParam.data.auto_first_support_id=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item></n-descriptions-item>
                <n-descriptions-item label="自动跟机尾架">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="自动跟机尾架"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.auto_tail_support_id"
                    @update:value="i=>publicParam.data.auto_tail_support_id=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item></n-descriptions-item>
              </n-descriptions>
            </n-space>
          </n-gi>

          <n-gi span="2">
            <n-divider dashed style="height:0px">自动跟机参数</n-divider>
            <n-space justify="space-around">
              <n-descriptions
                label-placement="left"
                bordered
                :column="2"
                label-align="center"
                size="small"
              >
                <n-descriptions-item label="自动跟机">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.auto_follow_machine_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.auto_follow_machine_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="移架距离(*0.1架)">
                  <n-space > 
                    <span style="text-align:center;font-size:medium;">{{bracing_method}}</span>
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="移架距离"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.moving_interval_distance"
                    @update:value="i=>publicParam.data.moving_interval_distance=i"
                  ></n-input-number></n-space>
                 
                </n-descriptions-item>
                <n-descriptions-item label="自动移架">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.automatic_rack_transfer_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.automatic_rack_transfer_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="推溜间隔">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="推溜间隔"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.pushing_interval_distance"
                    @update:value="i=>publicParam.data.pushing_interval_distance=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="自动推溜">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.automatic_push_and_slide_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.automatic_push_and_slide_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="收护帮板距离">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="收护帮板距离"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.spacing_distance_between_stop_guards"
                    @update:value="i=>publicParam.data.spacing_distance_between_stop_guards=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="自动护帮">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.automatic_guardboard_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.automatic_guardboard_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="伸护帮板距离">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="伸护帮板距离"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.spacing_distance_between_stretch_guards"
                    @update:value="i=>publicParam.data.spacing_distance_between_stretch_guards=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="自动推端头">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.automatic_push_end_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.automatic_push_end_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="喷雾距离">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="喷雾距离"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.spray_interval_distance"
                    @update:value="i=>publicParam.data.spray_interval_distance=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="自动喷雾">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.automatic_spray_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.automatic_spray_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="跳架停机距离">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="跳架停机距离"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.jump_protection_distance"
                    @update:value="i=>publicParam.data.jump_protection_distance=i"
                  ></n-input-number>
                </n-descriptions-item>
              </n-descriptions>
            </n-space>
          </n-gi>
          
          <n-gi span="2">
            <n-divider dashed style="height:0px">辅助自动化参数</n-divider>
            <n-space justify="space-around">
              <n-descriptions
                label-placement="left"
                bordered
                :column="2"
                label-align="right"
                size="small"
              >
                <n-descriptions-item label="自动补压">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.auto_compensation_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.auto_compensation_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="自动反冲洗">
                  <n-switch
                    :disabled="publicParamLoading"
                    :loading="publicParamLoading"
                    size="small"
                    :value="publicParam.data.automatic_backwash_enable"
                    :checked-value="1"
                    :unchecked-value="0"
                    :round="false"
                    @update:value="i=>publicParam.data.automatic_backwash_enable=i"
                  >
                    <template #checked>开</template>
                    <template #unchecked>关</template>
                  </n-switch>
                </n-descriptions-item>
                <n-descriptions-item label="初撑压力(MPa)">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="初撑压力"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.initial_pressure_setting"
                    @update:value="i=>publicParam.data.initial_pressure_setting=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item label="反冲洗周期(HH:mm)">
                  <span
                  style="text-align:center;font-size:medium;"
                  >{{publicParam.data.auto_backwash_remaining_h}}:{{publicParam.data.auto_backwash_remaining_m}}</span>
                </n-descriptions-item>
                <n-descriptions-item label="过渡压力(MPa)">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="过渡压力"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.transition_pressure_setting"
                    @update:value="i=>publicParam.data.transition_pressure_setting=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item></n-descriptions-item>
                <n-descriptions-item label="开始补压值(MPa)">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="补压开始阈值"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.suspension_start_threshold"
                    @update:value="i=>publicParam.data.suspension_start_threshold=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item></n-descriptions-item>
                <n-descriptions-item label="停止补压值(MPa)">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="停止补压值"
                    :min="0"
                    :max="999"
                    :value="publicParam.data.suspension_stop_threshold"
                    @update:value="i=>publicParam.data.suspension_stop_threshold=i"
                  ></n-input-number>
                </n-descriptions-item>
                <n-descriptions-item></n-descriptions-item>
                <n-descriptions-item label="自动补压周期(h)">
                  <n-input-number
                    style="width:90px"
                    size="small"
                    placeholder="小时"
                    :min="0"
                    :max="255"
                    :value="publicParam.data.automatic_refill_cycle"
                    @update:value="i=>publicParam.data.automatic_refill_cycle=i"
                  ></n-input-number>
