          </div>
        </span>
      </div>
      <n-modal v-model:show="loginFormVisiable" :mask-closable="false" preset="dialog" title="账户">
        <div class="view-index-container">
          <div class="view-index-top">
            <div class="view-index-top-logo">
              <img src="~@/assets/images/lianli.png" alt="联力" />
            </div>
            <div class="view-index-top-desc">支架电液控</div>
          </div>
          <div class="view-index-form">
            <n-form ref="formRef" label-placement="left" size="large" :model="formInline">
              <n-form-item path="username">
