<script setup>
import { onMounted, ref } from "vue";
import { useWsStore } from "@/store/modules/websocket";
import { useRouter,useRoute } from "vue-router";
import { useMessage, useNotification } from "naive-ui";
import { messageModelStore } from "@/store/modules/messageModel";
import { useUserStore } from "@/store/modules/user";
import { PersonOutline, LockClosedOutline } from "@vicons/ionicons5";
import { login } from "@/api/user";

const nMessage = useMessage();
const notify = useNotification();
const messageModel = messageModelStore();
messageModel.setUseMessage(nMessage);
messageModel.setUseNotification(notify);
const router = useRouter();
const route = useRoute();
const useUser = useUserStore();
const wsStore = useWsStore();
wsStore.init();
console.log("route",router)
//控制弹窗弹出
const loginFormVisiable = ref(false);
//const formRef = ref();
const formInline = ref({
  username: "",
  password: "",
});
useUser.refresh();
const userLogin = async () => {
  let { code, message } = await login(formInline.value);
  //console.log('@@',code)
  if (code == 0) {
    await useUser.login(message);
    loginFormVisiable.value = false;
  } else {
    nMessage.info("密码不正确！");
  }
};
onMounted(() => {});
</script>

