import axios from 'axios'
import { messageModelStore } from "../store/modules/messageModel"
import { useUserStore } from "../store/modules/user"
import { store } from "../store"
const service = axios.create({
    baseURL: "/api"
})
const messageModel = messageModelStore(store)
const userStore = useUserStore(store)
//添加请求拦截器
service.interceptors.request.use(
    config => {
        console.log(userStore.uuid)
        if (userStore.uuid != "") {
            config.headers['uuid'] = userStore.uuid
        }
        return config
    },
    //请求错误后的操作
    error => {
        console.log(error) // for debug
        return Promise.reject(error)
    }
)
//添加响应拦截器
service.interceptors.response.use(response => {
    return response.data
}, error => {
    messageModel.useMessage.warning('请求失败，请检查网络')
    return Promise.reject(error)
})
export default service
